import{_ as t,o as r,c as d,aa as c}from"./chunks/framework.vXJbu8_U.js";const p=JSON.parse('{"title":"Миграция","description":"","frontmatter":{},"headers":[],"relativePath":"ru/guide/migration.md","filePath":"ru/guide/migration.md","lastUpdated":1781019088000}'),o={name:"ru/guide/migration.md"};function a(i,e,s,n,l,h){return r(),d("div",null,[...e[0]||(e[0]=[c(`<h1 id="миграция" tabindex="-1">Миграция <a class="header-anchor" href="#миграция" aria-label="Permalink to &quot;Миграция&quot;">​</a></h1><h2 id="кодмод-автоматически" tabindex="-1">Кодмод (автоматически) <a class="header-anchor" href="#кодмод-автоматически" aria-label="Permalink to &quot;Кодмод (автоматически)&quot;">​</a></h2><p>Кодмод берёт на себя механическую часть — переписывает импорты и сворачивает standalone-операторы в inline-конфиг <code>createQuery</code>:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npx</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> effector-refetch-codemod</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;src/**/*.{ts,tsx}&quot;</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npx</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> effector-refetch-codemod</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;src/**/*.ts&quot;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --dry</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">   # только предпросмотр</span></span></code></pre></div><p>Он переписывает <code>@farfetched/core</code> → <code>effector-refetch</code>, превращает <code>retry(q, …)</code> / <code>cache(q, …)</code> / <code>concurrency(q, { strategy })</code> в <code>createQuery({ retry, cache, concurrency })</code> и убирает ставшие ненужными импорты операторов. Операторы на запросе, который нельзя разрешить статически, остаются как есть — просмотрите дифф и прогоните форматтер. Остальное покрывает ручная таблица ниже.</p><h2 id="с-farfetched" tabindex="-1">С farfetched <a class="header-anchor" href="#с-farfetched" aria-label="Permalink to &quot;С farfetched&quot;">​</a></h2><p>Модель близка, поэтому большая часть кода переносится напрямую. Главный сдвиг: <strong>приносите свой эффект</strong>, а inline-опции доступны наравне с операторами.</p><table tabindex="0"><thead><tr><th>farfetched</th><th>effector-refetch</th></tr></thead><tbody><tr><td><code>createQuery({ handler })</code></td><td><code>createQuery({ effect })</code> (или <code>{ handler }</code>)</td></tr><tr><td><code>createJsonQuery({ ... })</code></td><td><code>createJsonQuery({ request, response })</code></td></tr><tr><td><code>retry(query, { times, delay })</code></td><td><code>retry(query, …)</code> <strong>или</strong> inline <code>createQuery({ retry })</code></td></tr><tr><td><code>cache(query, { ... })</code></td><td><code>cache(query, …)</code> <strong>или</strong> inline <code>createQuery({ cache })</code></td></tr><tr><td><code>concurrency(query, { strategy })</code></td><td><code>concurrency(query, …)</code> <strong>или</strong> inline <code>createQuery({ concurrency })</code></td></tr><tr><td><code>connectQuery({ source, fn, target })</code></td><td>идентично</td></tr><tr><td><code>createMutation</code></td><td><code>createMutation</code> (+ алиас <code>mutate</code>)</td></tr><tr><td>контракты</td><td><code>zodContract</code> / <code>standardSchemaContract</code> / <code>createContract</code></td></tr><tr><td><code>$data / $error / $status / $pending</code></td><td>те же имена</td></tr></tbody></table><p>Заметные отличия:</p><ul><li>Query оборачивает <strong>реальный эффект</strong> (<code>query.__.effect</code>), видимый в devtools.</li><li>Отмена реальная для эффектов из <code>createRequestFx</code> (AbortSignal), а не только discard.</li><li>Sourced-конфиг доступен inline (<code>Store</code> для <code>concurrency</code> / <code>retry.times</code> / <code>cache.staleAfter</code> / <code>enabled</code>).</li><li><code>useUnit(query)</code> работает напрямую в React и Vue через <code>@@unitShape</code>.</li></ul><p>Чего пока нет (в сравнении с farfetched): биндинг Solid, полная sourced-поверхность на каждом поле и часть удобств JSON-контрактов. См. <a href="https://github.com/Olovyannikov/effector-query/blob/main/ROADMAP.md" target="_blank" rel="noreferrer">roadmap</a>.</p><h2 id="внутри-0-x" tabindex="-1">Внутри 0.x <a class="header-anchor" href="#внутри-0-x" aria-label="Permalink to &quot;Внутри 0.x&quot;">​</a></h2><p>До 1.0 API ещё может меняться между минорными версиями; ломающие изменения отмечаются в changelog. Из заметного:</p><ul><li>Адаптеры web-storage теперь принимают <strong>объект опций</strong>: <code>localStorageCache({ version, maxAge })</code> (раньше — строку-префикс).</li></ul>`,14)])])}const f=t(o,[["render",a]]);export{p as __pageData,f as default};
